import { Accessor, createMemo } from "gnim"

export type $<T> = T | Accessor<T>

export function $<T>(value: $<T>): Accessor<T>
export function $<T, R>(value: $<T>, transform: (v: T) => R): Accessor<R>

export function $<T>(value: $<T>, transform?: (v: T) => T): Accessor<T> {
    if (transform) {
        if (value instanceof Accessor) {
            return createMemo(() => transform(value()))
        }
        const v = transform(value)
        return new Accessor(() => v)
    }

    return value instanceof Accessor ? value : new Accessor(() => value)
}
